from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismGetProjectConfigPathNode(BaseNode):
    name = "Prism: Get Project Config Path"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("project_path", "string", widget_type="file")
        self.add_output("config_path", "string")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        path = inputs.get('project_path') or ''
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'config_path': ''}
        try:
            cfg = ''
            if hasattr(core, 'configs') and hasattr(core.configs, 'getProjectConfigPath'):
                cfg = str(core.configs.getProjectConfigPath(path) or '')
            self.log_info(f"Config path: {cfg}")
            return {'config_path': cfg}
        except Exception as e:
            self.log_error(f"getProjectConfigPath failed: {e}")
            return {'config_path': ''}

def register_node():
    return PrismGetProjectConfigPathNode
